// // This module synchronizes outputs D and S to the rising edge of TxClk. On reset, D and S are set to HIGH (1). When Tx0 or Tx1 is asserted, D takes the value of Tx0, and S is updated based on the XOR of D and S.
module top_module(input TxClk, input TxReset, input Tx1, input Tx0, output reg D, output reg S);wire nextD = Tx1; 
  wire nextS = (Tx0 & ~(D^S)) | (Tx1 & (D^S)); 

  always @(posedge TxClk or posedge TxReset) begin 
    if(TxReset) begin 
      D <= 1'b0; 
      S <= 1'b0; 
    end 
    else if(Tx0 | Tx1) begin 
      D <= nextD; 
      S <= nextS; 
    end 
  end 
endmodule
